CREATE OR REPLACE FUNCTION fpa_tel_get_date_kep_amount (as_memno char) RETURNS timestamp(0) AS $body$
DECLARE

ldt_operate_date timestamp(0);
li_count integer;
type tabrowi_shrdet is table of sc_mem_m_share_holding_detail%rowtype index by integer;
ltabrowi_shrdet tabrowi_shrdet;
BEGIN
  select * bulk collect into STRICT ltabrowi_shrdet from sc_mem_m_share_holding_detail where membership_no = as_memno order by seq_no;
  li_count := ltabrowi_shrdet.count;
  --ไปหาจากวันที่มีการชำระพิเศษ
  for i in 1..li_count loop
    if ltabrowi_shrdet[i].item_type = 'SB' and ltabrowi_shrdet[i+1].item_type <> 'RX' then
       ldt_operate_date := ltabrowi_shrdet[i].operate_date;
       goto end_loop;
    end if;
  end loop;
  --ต้องไม่มีการยกเลิกใบเสร็จ
  for i in 1..li_count loop
    if ltabrowi_shrdet[i].item_type = 'MS' and ltabrowi_shrdet[i+1].item_type <> 'RM' then
       ldt_operate_date := ltabrowi_shrdet[i].operate_date;
       goto end_loop;
    end if;
  end loop;

  <<End_loop>>
  return ldt_operate_date;

 exception
   when no_data_found then return to_date('1/1/1900','dd/mm/yyyy');
   when others then CALL spa_dberror('FPA_TEL_GET_DATE_KEP_AMOUNT');

END;
$body$
